// eslint-disable-next-line @typescript-eslint/no-explicit-any
function serialize(val: any) {
  return JSON.stringify(val);
}

function deserialize(val: string) {
  if (typeof val !== 'string') {
    return undefined;
  }
  try {
    return JSON.parse(val);
  } catch (e) {
    /* istanbul ignore next */
    return val || undefined;
  }
}

class Store {
  get(key: string) {
    if (!localStorage || !localStorage.getItem) return;

    return deserialize(localStorage.getItem(key));
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  set(key: string, val: any) {
    if (!localStorage || !localStorage.setItem) return;

    localStorage.setItem(key, serialize(val));
  }

  del(key: string) {
    if (!localStorage || !localStorage.removeItem) return;

    localStorage.removeItem(key);
  }
}

export const store = new Store();
